182	/* (internal) Instanciate an instance for a single class and initialize variables to nil */
183	static binstance* newobjself(bvm *vm, bclass *c)
184	{
185	    size_t size = sizeof(binstance) + sizeof(bvalue) * (c->nvar - 1);
186	    bgcobject *gco = be_newgcobj(vm, BE_INSTANCE, size);
187	    binstance *obj = cast_instance(gco);
188	    be_assert(obj != NULL);
189	    if (obj) { /* initialize members */
190	        bvalue *v = obj->members, *end = v + c->nvar;  /* instance variables is a simple array of pointers at obj->members of size c->nvar */
191	        while (v < end) { var_setnil(v); ++v; }  /* Initialize all instance variables to `nil` */
192	        obj->_class = c;  /* set its class object */
193	        obj->super = NULL;  /* no super class instance for now */
194	        obj->sub = NULL;  /* no subclass instance for now */
195	    }
196	    return obj;
197	}
198	
199	/* (internal) Instanciate the whole chain of instances when there is a class hierarchy */
200	/* All variables set to nil, constructors are not called here */
201	static binstance* newobject(bvm *vm, bclass *c)
202	{
203	    binstance *obj, *prev;
204	    be_assert(c != NULL);
205	    obj = prev = newobjself(vm, c);
206	    var_setinstance(vm->top, obj);
207	    be_incrtop(vm); /* protect new objects from GC */
208	    for (c = c->super; c; c = c->super) {  /* initialize one instance object per class and per superclass */
209	        prev->super = newobjself(vm, c);
210	        prev->super->sub = prev;  /* link the super/sub classes instances */
211	        prev = prev->super;
212	    }
213	    be_stackpop(vm, 1);
214	    return obj;
215	}
