217	/* Instanciate new instance from stack with argc parameters */
218	/* Pushes the constructor on the stack to be executed if a construtor is found */
219	/* Returns true if a constructor is found */
220	bbool be_class_newobj(bvm *vm, bclass *c, bvalue *reg, int argc, int mode)
221	{
222	    bvalue init;
223	    size_t pos = reg - vm->reg;
224	    binstance *obj = newobject(vm, c);  /* create empty object hierarchy from class hierarchy */
225	    reg = vm->reg + pos - mode; /* the stack may have changed, mode=1 when class is instanciated from module #104 */
226	    var_setinstance(reg, obj);
227	    var_setinstance(reg + mode, obj);  /* copy to reg and reg+1 if mode==1 */
228	    /* find constructor */
229	    obj = instance_member(vm, obj, str_literal(vm, "init"), &init);
230	    if (obj && var_type(&init) != MT_VARIABLE) {
231	        /* copy argv */
232	        for (reg = vm->reg + pos + 1; argc > 0; --argc) {
233	            reg[argc] = reg[argc - 2];
234	        }
235	        *reg = init; /* set constructor */
236	        return btrue;
237	    }
238	    return bfalse;
239	}
