 309	    int type = be_module_attr(vm, module, attr, dst);
 310	    if (type == BE_NONE) {
 311	        vm_error(vm, "attribute_error",
 312	            "module '%s' has no member '%s'",
 313	            be_module_name(module), str(attr));
 314	    }
 315	    return type;
 316	}
