1131	    // push_closure(vm, reg, proto->nstack, 0);
1132	    // v = vm->reg + argc;
1133	    // end = vm->reg + proto->argc;
1134	    // for (; v <= end; ++v) {
1135	    //     var_setnil(v);
1136	    // }
1137	    prep_closure(vm, reg, argc, 0);
1138	    vm_exec(vm);
