1141	static void do_ntvclos(bvm *vm, bvalue *reg, int argc)
1142	{
1143	    bntvclos *f = var_toobj(reg);
1144	    push_native(vm, reg, argc, 0);
1145	    f->f(vm); /* call C primitive function */
1146	    ret_native(vm);
