1149	static void do_ntvfunc(bvm *vm, bvalue *reg, int argc)
1150	{
1151	    bntvfunc f = var_tontvfunc(reg);
1152	    push_native(vm, reg, argc, 0);
1153	    f(vm); /* call C primitive function */
1154	    ret_native(vm);
