1157	static void do_class(bvm *vm, bvalue *reg, int argc)
1158	{
1159	    if (be_class_newobj(vm, var_toobj(reg), reg, ++argc, 0)) {
1160	        be_incrtop(vm);
1161	        be_dofunc(vm, reg + 1, argc);
1162	        be_stackpop(vm, 1);
1163	    }
1164	}
1165	
1166	void be_dofunc(bvm *vm, bvalue *v, int argc)
1167	{
1168	    be_assert(vm->reg <= v && v < vm->stacktop);
1169	    be_assert(vm->stack <= vm->reg && vm->reg < vm->stacktop);
1170	    switch (var_type(v)) {
1171	    case BE_CLASS: do_class(vm, v, argc); break;
1172	    case BE_CLOSURE: do_closure(vm, v, argc); break;
1173	    case BE_NTVCLOS: do_ntvclos(vm, v, argc); break;
1174	    case BE_NTVFUNC: do_ntvfunc(vm, v, argc); break;
1175	    default: call_error(vm, v);
1176	    }
1177	}
